      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
}
function close$VoucherFilter$(f) {try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Checking':
      var x = f.getItemValue('mau_bc'), y = f.getItemValue('kieu_bc'), p = f.getItemValue('so_ky'), v = g._language == 'v', d = f.getItem('ngay_bd').value, r;
      switch (y) {
        case '1':
          r = (v ? 'theo ngày' : 'by Day');
          break;
        case '2':
          r = (v ? 'theo tuần' : 'by Week');
          break;
        case '3':
          r = (v ? 'theo tháng' : 'by Month');
          break;
        case '4':
          r = (v ? 'theo quý' : 'by Quarter');
          break;
        case '5':
          r = (v ? 'theo nửa năm' : 'by Half a Year');
          break;
        case '6':
          r = (v ? 'theo năm' : 'by Year');
          break;
        default:
          break;
      }
      x = f.getItem('form').selectedIndex, y = f.getItem('form').options;
      var formName = y[x].text;
      g._alterTitle = [null, [['%f1', formName, true], ['%r', r, true], ['%p', p, true], ['%d', d, true]]];

      var c = f.getItemValue('mau_bc') + String.fromCharCode(255) + p;
      if (!g._v) g._v = c;
      if (g._v != c) {
        remove$GridReport$Filter(g);
        g._v = c;
      }
      break;
    default:
      break;
  }
}
function initForm(f) {
  var o = f.getItem('form'), value = f._itemValue.split(String.fromCharCode(255)), text = f._itemText.split(String.fromCharCode(255)), index;
  for (var i = 0; i < value.length; i++) {
    o.options[i] = new Option(text[i], value[i]);
    if (!index && f._defaultForm == value[i]) index = i;
  }
  if (!index) index = 0;
  o.options[index].selected = true;
}
